207	func (c *hugoBuilder) initMemTicker() func() {
208		memticker := time.NewTicker(5 * time.Second)
209		quit := make(chan struct{})
210		printMem := func() {
211			var m runtime.MemStats
212			runtime.ReadMemStats(&m)
213			fmt.Printf("\n\nAlloc = %v\nTotalAlloc = %v\nSys = %v\nNumGC = %v\n\n", formatByteCount(m.Alloc), formatByteCount(m.TotalAlloc), formatByteCount(m.Sys), m.NumGC)
214		}
215	
216		go func() {
217			for {
218				select {
219				case <-memticker.C:
220					printMem()
221				case <-quit:
222					memticker.Stop()
223					printMem()
224					return
225				}
226			}
227		}()
228	
229		return func() {
230			close(quit)
231		}
232	}
