313	// newWatcher creates a new watcher to watch filesystem events.
314	func (c *hugoBuilder) newWatcher(pollIntervalStr string, dirList ...string) (*watcher.Batcher, error) {
315		staticSyncer := &staticSyncer{c: c}
316	
317		var pollInterval time.Duration
318		poll := pollIntervalStr != ""
319		if poll {
320			pollInterval, err := types.ToDurationE(pollIntervalStr)
321			if err != nil {
322				return nil, fmt.Errorf("invalid value for flag poll: %s", err)
323			}
324			c.r.logger.Printf("Use watcher with poll interval %v", pollInterval)
325		}
326	
327		if pollInterval == 0 {
328			pollInterval = 500 * time.Millisecond
329		}
330	
331		watcher, err := watcher.New(500*time.Millisecond, pollInterval, poll)
332		if err != nil {
333			return nil, err
334		}
335	
336		h, err := c.hugo()
337		if err != nil {
338			return nil, err
339		}
340		spec := h.Deps.SourceSpec
341	
342		for _, d := range dirList {
343			if d != "" {
344				if spec.IgnoreFile(d) {
345					continue
346				}
347				_ = watcher.Add(d)
348			}
349		}
350	
351		// Identifies changes to config (config.toml) files.
352		configSet := make(map[string]bool)
353		var configFiles []string
354		c.withConf(func(conf *commonConfig) {
355			configFiles = conf.configs.LoadingInfo.ConfigFiles
356		})
357	
358		c.r.Println("Watching for config changes in", strings.Join(configFiles, ", "))
359		for _, configFile := range configFiles {
360			watcher.Add(configFile)
361			configSet[configFile] = true
362		}
363	
364		go func() {
365			for {
366				select {
367				case changes := <-c.r.changesFromBuild:
368					unlock, err := h.LockBuild()
369					if err != nil {
370						c.r.logger.Errorf("Failed to acquire a build lock: %s", err)
371						return
372					}
373					c.changeDetector.PrepareNew()
374					err = c.rebuildSitesForChanges(changes)
375					if err != nil {
376						c.r.logger.Errorln("Error while watching:", err)
377					}
378					if c.s != nil && c.s.doLiveReload {
379						doReload := c.changeDetector == nil || len(c.changeDetector.changed()) > 0
380						doReload = doReload || c.showErrorInBrowser && c.errState.buildErr() != nil
381						if doReload {
382							livereload.ForceRefresh()
383						}
384					}
385					unlock()
386	
387				case evs := <-watcher.Events:
388					unlock, err := h.LockBuild()
389					if err != nil {
390						c.r.logger.Errorf("Failed to acquire a build lock: %s", err)
391						return
392					}
393					c.handleEvents(watcher, staticSyncer, evs, configSet)
394					if c.showErrorInBrowser && c.errState.buildErr() != nil {
395						// Need to reload browser to show the error
396						livereload.ForceRefresh()
397					}
398					unlock()
399				case err := <-watcher.Errors():
400					if err != nil && !herrors.IsNotExist(err) {
401						c.r.logger.Errorln("Error while watching:", err)
402					}
403				}
404			}
405		}()
406	
407		return watcher, nil
408	}
