410	func (c *hugoBuilder) build() error {
411		stopProfiling, err := c.initProfiling()
412		if err != nil {
413			return err
414		}
415	
416		defer func() {
417			if stopProfiling != nil {
418				stopProfiling()
419			}
420		}()
421	
422		if err := c.fullBuild(false); err != nil {
423			return err
424		}
425	
426		if !c.r.quiet {
427			c.r.Println()
428			h, err := c.hugo()
429			if err != nil {
430				return err
431			}
432	
433			h.PrintProcessingStats(os.Stdout)
434			c.r.Println()
435		}
436	
437		return nil
438	}
