517	func (c *hugoBuilder) doWithPublishDirs(f func(sourceFs *filesystems.SourceFilesystem) (uint64, error)) (map[string]uint64, error) {
518		langCount := make(map[string]uint64)
519	
520		h, err := c.hugo()
521		if err != nil {
522			return nil, err
523		}
524		staticFilesystems := h.BaseFs.SourceFilesystems.Static
525	
526		if len(staticFilesystems) == 0 {
527			c.r.logger.Infoln("No static directories found to sync")
528			return langCount, nil
529		}
530	
531		for lang, fs := range staticFilesystems {
532			cnt, err := f(fs)
533			if err != nil {
534				return langCount, err
535			}
536			if lang == "" {
537				// Not multihost
538				c.withConf(func(conf *commonConfig) {
539					for _, l := range conf.configs.Languages {
540						langCount[l.Lang] = cnt
541					}
542				})
543			} else {
544				langCount[lang] = cnt
545			}
546		}
547	
548		return langCount, nil
549	}
