691	func (c *hugoBuilder) handleEvents(watcher *watcher.Batcher,
692		staticSyncer *staticSyncer,
693		evs []fsnotify.Event,
694		configSet map[string]bool,
695	) {
696		defer func() {
697			c.errState.setWasErr(false)
698		}()
699	
700		var isHandled bool
701	
702		// Filter out ghost events (from deleted, renamed directories).
703		// This seems to be a bug in fsnotify, or possibly MacOS.
704		var n int
705		for _, ev := range evs {
706			keep := true
707			// Write and rename operations are often followed by CHMOD.
708			// There may be valid use cases for rebuilding the site on CHMOD,
709			// but that will require more complex logic than this simple conditional.
710			// On OS X this seems to be related to Spotlight, see:
711			// https://github.com/go-fsnotify/fsnotify/issues/15
712			// A workaround is to put your site(s) on the Spotlight exception list,
713			// but that may be a little mysterious for most end users.
714			// So, for now, we skip reload on CHMOD.
715			// We do have to check for WRITE though. On slower laptops a Chmod
716			// could be aggregated with other important events, and we still want
717			// to rebuild on those
718			if ev.Op == fsnotify.Chmod {
719				keep = false
720			} else if ev.Has(fsnotify.Create) || ev.Has(fsnotify.Write) {
721				if _, err := os.Stat(ev.Name); err != nil {
722					keep = false
723				}
724			}
725			if keep {
726				evs[n] = ev
727				n++
728			}
729		}
730		evs = evs[:n]
731	
732		for _, ev := range evs {
733			isConfig := configSet[ev.Name]
734			configChangeType := configChangeConfig
735			if isConfig {
736				if strings.Contains(ev.Name, "go.mod") {
737					configChangeType = configChangeGoMod
738				}
739				if strings.Contains(ev.Name, ".work") {
740					configChangeType = configChangeGoWork
741				}
742			}
743			if !isConfig {
744				// It may be one of the /config folders
745				dirname := filepath.Dir(ev.Name)
746				if dirname != "." && configSet[dirname] {
747					isConfig = true
748				}
749			}
750	
751			if isConfig {
752				isHandled = true
753	
754				if ev.Op&fsnotify.Chmod == fsnotify.Chmod {
755					continue
756				}
757	
758				if ev.Op&fsnotify.Remove == fsnotify.Remove || ev.Op&fsnotify.Rename == fsnotify.Rename {
759					c.withConf(func(conf *commonConfig) {
760						for _, configFile := range conf.configs.LoadingInfo.ConfigFiles {
761							counter := 0
762							for watcher.Add(configFile) != nil {
763								counter++
764								if counter >= 100 {
765									break
766								}
767								time.Sleep(100 * time.Millisecond)
768							}
769						}
770					})
771				}
772	
773				// Config file(s) changed. Need full rebuild.
774				c.fullRebuild(configChangeType)
775	
776				return
777			}
778		}
779	
780		if isHandled {
781			return
782		}
783	
784		if c.errState.isPaused() {
785			// Wait for the server to get into a consistent state before
786			// we continue with processing.
787			return
788		}
789	
790		if len(evs) > 50 {
791			// This is probably a mass edit of the content dir.
792			// Schedule a full rebuild for when it slows down.
793			c.debounce(func() {
794				c.fullRebuild("")
795			})
796			return
797		}
798	
799		c.r.logger.Debugln("Received System Events:", evs)
800	
801		staticEvents := []fsnotify.Event{}
802		dynamicEvents := []fsnotify.Event{}
803	
804		filterDuplicateEvents := func(evs []fsnotify.Event) []fsnotify.Event {
805			seen := make(map[string]bool)
806			var n int
807			for _, ev := range evs {
808				if seen[ev.Name] {
809					continue
810				}
811				seen[ev.Name] = true
812				evs[n] = ev
813				n++
814			}
815			return evs[:n]
816		}
817	
818		h, err := c.hugo()
819		if err != nil {
820			c.r.logger.Errorln("Error getting the Hugo object:", err)
821			return
822		}
823		n = 0
824		for _, ev := range evs {
825			if h.ShouldSkipFileChangeEvent(ev) {
826				continue
827			}
828			evs[n] = ev
829			n++
830		}
831		evs = evs[:n]
832	
833		for _, ev := range evs {
834			ext := filepath.Ext(ev.Name)
835			baseName := filepath.Base(ev.Name)
836			istemp := strings.HasSuffix(ext, "~") ||
837				(ext == ".swp") || // vim
838				(ext == ".swx") || // vim
839				(ext == ".bck") || // helix
840				(ext == ".tmp") || // generic temp file
841				(ext == ".DS_Store") || // OSX Thumbnail
842				baseName == "4913" || // vim
843				strings.HasPrefix(ext, ".goutputstream") || // gnome
844				strings.HasSuffix(ext, "jb_old___") || // intelliJ
845				strings.HasSuffix(ext, "jb_tmp___") || // intelliJ
846				strings.HasSuffix(ext, "jb_bak___") || // intelliJ
847				strings.HasPrefix(ext, ".sb-") || // byword
848				strings.HasPrefix(baseName, ".#") || // emacs
849				strings.HasPrefix(baseName, "#") // emacs
850			if istemp {
851				continue
852			}
853	
854			if h.Deps.SourceSpec.IgnoreFile(ev.Name) {
855				continue
856			}
857			// Sometimes during rm -rf operations a '"": REMOVE' is triggered. Just ignore these
858			if ev.Name == "" {
859				continue
860			}
861	
862			walkAdder := func(ctx context.Context, path string, f hugofs.FileMetaInfo) error {
863				if f.IsDir() {
864					c.r.logger.Println("adding created directory to watchlist", path)
865					if err := watcher.Add(path); err != nil {
866						return err
867					}
868				} else if !staticSyncer.isStatic(h, path) {
869					// Hugo's rebuilding logic is entirely file based. When you drop a new folder into
870					// /content on OSX, the above logic will handle future watching of those files,
871					// but the initial CREATE is lost.
872					dynamicEvents = append(dynamicEvents, fsnotify.Event{Name: path, Op: fsnotify.Create})
873				}
874				return nil
875			}
876	
877			// recursively add new directories to watch list
878			if ev.Has(fsnotify.Create) || ev.Has(fsnotify.Rename) {
879				c.withConf(func(conf *commonConfig) {
880					if s, err := conf.fs.Source.Stat(ev.Name); err == nil && s.Mode().IsDir() {
881						_ = helpers.Walk(conf.fs.Source, ev.Name, walkAdder)
882					}
883				})
884			}
885	
886			if staticSyncer.isStatic(h, ev.Name) {
887				staticEvents = append(staticEvents, ev)
888			} else {
889				dynamicEvents = append(dynamicEvents, ev)
890			}
891		}
892	
893		lrl := c.r.logger.InfoCommand("livereload")
894	
895		staticEvents = filterDuplicateEvents(staticEvents)
896		dynamicEvents = filterDuplicateEvents(dynamicEvents)
897	
898		if len(staticEvents) > 0 {
899			c.printChangeDetected("Static files")
900	
901			if c.r.forceSyncStatic {
902				c.r.logger.Printf("Syncing all static files\n")
903				_, err := c.copyStatic()
904				if err != nil {
905					c.r.logger.Errorln("Error copying static files to publish dir:", err)
906					return
907				}
908			} else {
909				if err := staticSyncer.syncsStaticEvents(staticEvents); err != nil {
910					c.r.logger.Errorln("Error syncing static files to publish dir:", err)
911					return
912				}
913			}
914	
915			if c.s != nil && c.s.doLiveReload {
916				// Will block forever trying to write to a channel that nobody is reading if livereload isn't initialized
917	
918				if !c.errState.wasErr() && len(staticEvents) == 1 {
919					h, err := c.hugo()
920					if err != nil {
921						c.r.logger.Errorln("Error getting the Hugo object:", err)
922						return
923					}
924	
925					path := h.BaseFs.SourceFilesystems.MakeStaticPathRelative(staticEvents[0].Name)
926					path = h.RelURL(paths.ToSlashTrimLeading(path), false)
927	
928					lrl.Logf("refreshing static file %q", path)
929					livereload.RefreshPath(path)
930				} else {
931					lrl.Logf("got %d static file change events, force refresh", len(staticEvents))
932					livereload.ForceRefresh()
933				}
934			}
935		}
936	
937		if len(dynamicEvents) > 0 {
938			partitionedEvents := partitionDynamicEvents(
939				h.BaseFs.SourceFilesystems,
940				dynamicEvents)
941	
942			onePageName := pickOneWriteOrCreatePath(h.Conf.ContentTypes(), partitionedEvents.ContentEvents)
943	
944			c.printChangeDetected("")
945			c.changeDetector.PrepareNew()
946	
947			func() {
948				defer c.postBuild("Total", time.Now())
949				if err := c.rebuildSites(dynamicEvents); err != nil {
950					c.handleBuildErr(err, "Rebuild failed")
951				}
952			}()
953	
954			if c.s != nil && c.s.doLiveReload {
955				if c.errState.wasErr() {
956					livereload.ForceRefresh()
957					return
958				}
959	
960				changed := c.changeDetector.changed()
961				if c.changeDetector != nil {
962					if len(changed) >= 10 {
963						lrl.Logf("build changed %d files", len(changed))
964					} else {
965						lrl.Logf("build changed %d files: %q", len(changed), changed)
966					}
967					if len(changed) == 0 {
968						// Nothing has changed.
969						return
970					}
971				}
972	
973				// If this change set also contains one or more CSS files, we need to
974				// refresh these as well.
975				var cssChanges []string
976				var otherChanges []string
977	
978				for _, ev := range changed {
979					if strings.HasSuffix(ev, ".css") {
980						cssChanges = append(cssChanges, ev)
981					} else {
982						otherChanges = append(otherChanges, ev)
983					}
984				}
985	
986				if len(partitionedEvents.ContentEvents) > 0 {
987					navigate := c.s != nil && c.s.navigateToChanged
988					// We have fetched the same page above, but it may have
989					// changed.
990					var p page.Page
991	
992					if navigate {
993						if onePageName != "" {
994							p = h.GetContentPage(onePageName)
995						}
996					}
997	
998					if p != nil && p.RelPermalink() != "" {
999						link, port := p.RelPermalink(), p.Site().ServerPort()
1000						lrl.Logf("navigating to %q using port %d", link, port)
1001						livereload.NavigateToPathForPort(link, port)
1002					} else {
1003						lrl.Logf("no page to navigate to, force refresh")
1004						livereload.ForceRefresh()
1005					}
1006				} else if len(otherChanges) > 0 || len(cssChanges) > 0 {
1007					if len(otherChanges) == 1 {
1008						// Allow single changes to be refreshed without a full page reload.
1009						pathToRefresh := h.PathSpec.RelURL(paths.ToSlashTrimLeading(otherChanges[0]), false)
1010						lrl.Logf("refreshing %q", pathToRefresh)
1011						livereload.RefreshPath(pathToRefresh)
1012					} else if len(cssChanges) == 0 || len(otherChanges) > 1 {
1013						lrl.Logf("force refresh")
1014						livereload.ForceRefresh()
1015					}
1016				} else {
1017					lrl.Logf("force refresh")
1018					livereload.ForceRefresh()
1019				}
1020	
1021				if len(cssChanges) > 0 {
1022					// Allow some time for the live reload script to get reconnected.
1023					if len(otherChanges) > 0 {
1024						time.Sleep(200 * time.Millisecond)
1025					}
1026					for _, ev := range cssChanges {
1027						pathToRefresh := h.PathSpec.RelURL(paths.ToSlashTrimLeading(ev), false)
1028						lrl.Logf("refreshing CSS %q", pathToRefresh)
1029						livereload.RefreshPath(pathToRefresh)
1030					}
1031				}
1032			}
1033		}
1034	}
