1070	func (c *hugoBuilder) loadConfig(cd *simplecobra.Commandeer, running bool) error {
1071		if terminal.PrintANSIColors(os.Stdout) {
1072			defer c.progressHidden()
1073			// If the configuration takes a while to load, we want to show some progress.
1074			// This is typically loading of external modules.
1075			d := debounce.New(500 * time.Millisecond)
1076			d(func() {
1077				c.progressIntermediate()
1078			})
1079			defer d(func() {})
1080		}
1081	
1082		cfg := config.New()
1083		cfg.Set("renderToMemory", c.r.renderToMemory)
1084		watch := c.r.buildWatch || (c.s != nil && c.s.serverWatch)
1085		// We need to set the environment as early as possible because we need it to load the correct config.
1086		c.r.resolveEnvironment(c.s != nil)
1087		cfg.Set("environment", c.r.environment)
1088	
1089		cfg.Set("internal", hmaps.Params{
1090			"running":        running,
1091			"watch":          watch,
1092			"verbose":        c.r.isVerbose(),
1093			"fastRenderMode": c.fastRenderMode,
1094		})
1095	
1096		conf, err := c.r.ConfigFromProvider(configKey{counter: c.r.configVersionID.Load()}, flagsToCfg(cd, cfg))
1097		if err != nil {
1098			return err
1099		}
1100	
1101		if len(conf.configs.LoadingInfo.ConfigFiles) == 0 {
1102			//lint:ignore ST1005 end user message.
1103			return errors.New("Unable to locate config file or config directory. Perhaps you need to create a new project.\nRun `hugo help new` for details.")
1104		}
1105	
1106		c.conf = conf
1107		c.confOld = conf
1108		if c.onConfigLoaded != nil {
1109			if err := c.onConfigLoaded(false); err != nil {
1110				return err
1111			}
1112		}
1113	
1114		return nil
1115	}
