1119	func (c *hugoBuilder) printChangeDetected(typ string) {
1120		msg := "\nChange"
1121		if typ != "" {
1122			msg += " of " + typ
1123		}
1124		msg += fmt.Sprintf(" detected, rebuilding site (#%d).", rebuildCounter.Add(1))
1125	
1126		c.r.logger.Println(msg)
1127		const layout = "2006-01-02 15:04:05.000 -0700"
1128		c.r.logger.Println(htime.Now().Format(layout))
1129	}
