1150	func (c *hugoBuilder) rebuildSitesForChanges(ids []identity.Identity) (err error) {
1151		defer func() {
1152			c.errState.setBuildErr(err)
1153		}()
1154	
1155		var h *hugolib.HugoSites
1156		h, err = c.hugo()
1157		if err != nil {
1158			return
1159		}
1160		whatChanged := &hugolib.WhatChanged{}
1161		whatChanged.Add(ids...)
1162		err = h.Build(hugolib.BuildCfg{NoBuildLock: true, WhatChanged: whatChanged, RecentlyTouched: c.visitedURLs, ErrRecovery: c.errState.wasErr()})
1163	
1164		return
1165	}
